529→### 2.4 Layer 3: Statistical Anomaly Detection (Batch)
530→
531→```typescript
532→// lib/server/gpsAnomalyDetection.ts
533→// Runs as a scheduled job (daily via Vercel Cron)
534→
535→interface AgentMovementProfile {
536→  userId: string;
537→  totalSubmissions: number;
538→  uniqueLocations: number;
539→  averageDistanceBetweenSubmissionsKm: number;
540→  maxDistanceBetweenConsecutiveSubmissionsKm: number;
541→  averageSpeedKmh: number;
542→  maxSpeedKmh: number;
543→  clusterCount: number;           // Number of distinct location clusters
544→  primaryClusterCentroid: SubmissionLocation | null;
545→  submissionRadiusKm: number;     // 95th percentile distance from centroid
546→  precisionDistribution: {
547→    exactFourDecimals: number;    // Suspiciously round coordinates
548→    fiveOrMoreDecimals: number;   // Normal GPS precision
549→  };
550→  anomalyFlags: string[];
551→}
552→
553→async function analyzeAgentMovementPatterns(
554→  userId: string,
555→  windowDays: number = 30
556→): Promise<AgentMovementProfile> {
557→  const submissions = await getSubmissionsByUserInWindow(userId, windowDays);
558→  const profile: AgentMovementProfile = {
559→    userId,
560→    totalSubmissions: submissions.length,
561→    uniqueLocations: 0,
562→    averageDistanceBetweenSubmissionsKm: 0,
563→    maxDistanceBetweenConsecutiveSubmissionsKm: 0,
564→    averageSpeedKmh: 0,
565→    maxSpeedKmh: 0,
566→    clusterCount: 0,
567→    primaryClusterCentroid: null,
568→    submissionRadiusKm: 0,
569→    precisionDistribution: { exactFourDecimals: 0, fiveOrMoreDecimals: 0 },
570→    anomalyFlags: [],
571→  };
572→
573→  if (submissions.length < 3) return profile;
574→
575→  // ── COORDINATE PRECISION ANALYSIS ──
576→  // Spoofing apps often generate coordinates with suspiciously
577→  // uniform precision (e.g., always exactly 6 decimal places)
578→  // or suspiciously round values (4 decimal places = ~11m precision)
579→  for (const sub of submissions) {
580→    const latStr = sub.latitude.toString();
581→    const lonStr = sub.longitude.toString();
582→    const latDecimals = latStr.includes('.') ? latStr.split('.')[1].replace(/0+$/, '').length : 0;
583→    const lonDecimals = lonStr.includes('.') ? lonStr.split('.')[1].replace(/0+$/, '').length : 0;
584→    if (latDecimals <= 4 && lonDecimals <= 4) {
585→      profile.precisionDistribution.exactFourDecimals++;
586→    } else {
587→      profile.precisionDistribution.fiveOrMoreDecimals++;
588→    }
589→  }
590→
591→  // Flag: >80% of coordinates have suspiciously low precision
592→  const lowPrecisionRatio = profile.precisionDistribution.exactFourDecimals / submissions.length;
593→  if (lowPrecisionRatio > 0.8 && submissions.length >= 10) {
594→    profile.anomalyFlags.push('PRECISION_ANOMALY: >80% of GPS coordinates have <=4 decimal places');
595→  }
596→
597→  // ── CONSECUTIVE DISTANCE AND SPEED ANALYSIS ──
598→  const sortedByTime = [...submissions].sort(
599→    (a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()

600→  );
601→
602→  const distances: number[] = [];
603→  const speeds: number[] = [];
604→
605→  for (let i = 1; i < sortedByTime.length; i++) {
606→    const dist = haversineKm(
607→      { latitude: sortedByTime[i - 1].latitude, longitude: sortedByTime[i - 1].longitude },
608→      { latitude: sortedByTime[i].latitude, longitude: sortedByTime[i].longitude }
609→    );
610→    distances.push(dist);
611→
612→    const timeH = (new Date(sortedByTime[i].createdAt).getTime() -
613→                   new Date(sortedByTime[i - 1].createdAt).getTime()) / 3600000;
614→    if (timeH > 0) {
615→      speeds.push(dist / timeH);
616→    }
617→  }
618→
619→  profile.averageDistanceBetweenSubmissionsKm =
620→    distances.reduce((a, b) => a + b, 0) / distances.length;
621→  profile.maxDistanceBetweenConsecutiveSubmissionsKm = Math.max(...distances);
622→
623→  if (speeds.length > 0) {
624→    profile.averageSpeedKmh = speeds.reduce((a, b) => a + b, 0) / speeds.length;
625→    profile.maxSpeedKmh = Math.max(...speeds);
626→  }
627→
628→  // Flag: impossible max speed
629→  if (profile.maxSpeedKmh > 200) {
630→    profile.anomalyFlags.push(
631→      `IMPOSSIBLE_TRAVEL: Max speed ${profile.maxSpeedKmh.toFixed(0)} km/h`
632→    );
633→  }
634→
635→  // ── LOCATION CLUSTERING (Simple DBSCAN-like) ──
636→  // Cluster submissions within 200m of each other
637→  const clusters = clusterLocations(
638→    sortedByTime.map(s => ({ latitude: s.latitude, longitude: s.longitude })),
639→    0.2 // 200m cluster radius in km
640→  );
641→  profile.clusterCount = clusters.length;
642→
643→  // Unique locations: clusters + unclustered points
644→  const uniqueSet = new Set(
645→    sortedByTime.map(s => `${s.latitude.toFixed(5)},${s.longitude.toFixed(5)}`)
646→  );
647→  profile.uniqueLocations = uniqueSet.size;
648→
649→  // Flag: very few unique locations relative to submissions
650→  if (submissions.length >= 10 && profile.uniqueLocations < submissions.length * 0.3) {
651→    profile.anomalyFlags.push(
652→      `LOW_LOCATION_DIVERSITY: ${profile.uniqueLocations} unique locations for ${submissions.length} submissions`
653→    );
654→  }
655→
656→  // Primary cluster centroid
657→  if (clusters.length > 0) {
658→    const largest = clusters.sort((a, b) => b.length - a.length)[0];
659→    profile.primaryClusterCentroid = {
660→      latitude: largest.reduce((sum, p) => sum + p.latitude, 0) / largest.length,
661→      longitude: largest.reduce((sum, p) => sum + p.longitude, 0) / largest.length,
662→    };
663→  }
664→
665→  return profile;
666→}
667→
668→// Simple clustering: group points within radiusKm of each other
669→function clusterLocations(
670→  points: SubmissionLocation[],
671→  radiusKm: number
672→): SubmissionLocation[][] {
673→  const visited = new Set<number>();
674→  const clusters: SubmissionLocation[][] = [];
675→
676→  for (let i = 0; i < points.length; i++) {
677→    if (visited.has(i)) continue;
678→    visited.add(i);
679→    const cluster: SubmissionLocation[] = [points[i]];
680→
681→    for (let j = i + 1; j < points.length; j++) {
682→      if (visited.has(j)) continue;
683→      if (haversineKm(points[i], points[j]) <= radiusKm) {
684→        visited.add(j);
685→        cluster.push(points[j]);
686→      }
687→    }
688→
689→    if (cluster.length >= 2) {
690→      clusters.push(cluster);
691→    }
692→  }
693→
694→  return clusters;
695→}
