814→    gpsLon: metadata.gps?.longitude ?? null,
815→  };
816→  return createHash('sha256').update(JSON.stringify(fp)).digest('hex');
817→}
818→
819→// ── DUPLICATE CHECK PIPELINE ──
820→
821→interface DuplicateCheckResult {
822→  isDuplicate: boolean;
823→  duplicateType: 'exact' | 'perceptual' | 'exif_match' | 'none';
824→  matchedEventIds: string[];
825→  matchedPointIds: string[];
826→  confidence: number;  // 0-100
827→  action: 'allow' | 'flag' | 'reject';
828→  reason: string | null;
829→}
830→
831→async function checkPhotoDuplicate(params: {
832→  imageBuffer: Buffer;
833→  currentPointId: string;
834→  currentUserId: string;
835→  photoMetadata: ExtractedPhotoMetadata;
836→}): Promise<DuplicateCheckResult> {
837→  const sha256 = computeSHA256(params.imageBuffer);
838→  const pHash = computePerceptualHash(params.imageBuffer);
839→  const exifFp = computeExifFingerprint(params.photoMetadata);
840→
841→  // ── Step 1: Exact SHA-256 match ──
842→  const exactMatches = await findSubmissionsByImageHash(sha256);
843→  if (exactMatches.length > 0) {
844→    const samePoint = exactMatches.filter(e => e.pointId === params.currentPointId);
845→    const differentPoint = exactMatches.filter(e => e.pointId !== params.currentPointId);
846→
847→    if (differentPoint.length > 0) {
848→      // Same photo used for DIFFERENT entities -- strong fraud signal
849→      return {

 850→        isDuplicate: true,
 851→        duplicateType: 'exact',
 852→        matchedEventIds: differentPoint.map(e => e.eventId),
 853→        matchedPointIds: [...new Set(differentPoint.map(e => e.pointId))],
 854→        confidence: 99,
 855→        action: 'reject',
 856→        reason: `Exact duplicate photo already used for ${differentPoint.length} other submission(s)`,
 857→      };
 858→    }
 859→
 860→    if (samePoint.length > 0) {
 861→      // Same photo for same entity (re-enrichment) -- allow with flag
 862→      return {
 863→        isDuplicate: true,
 864→        duplicateType: 'exact',
 865→        matchedEventIds: samePoint.map(e => e.eventId),
 866→        matchedPointIds: [params.currentPointId],
 867→        confidence: 99,
 868→        action: 'flag',
 869→        reason: 'Same photo resubmitted for the same entity',
 870→      };
 871→    }
 872→  }
 873→
 874→  // ── Step 2: Perceptual hash near-match ──
 875→  // Query all perceptual hashes and find close matches
 876→  // In production, use a BK-tree or VP-tree for efficient nearest-neighbor
 877→  const allHashes = await getAllPerceptualHashes();
 878→  for (const existing of allHashes) {
 879→    if (existing.eventId === params.currentPointId) continue;
 880→    const distance = hammingDistance(pHash, existing.perceptualHash);
 881→
 882→    // Hamming distance thresholds for 64-bit hash:
 883→    //   0-5: near-identical (same image, different compression)
 884→    //   6-10: similar (same scene, different angle or crop)
 885→    //   >10: different images
 886→    if (distance <= 5 && existing.pointId !== params.currentPointId) {
 887→      return {
 888→        isDuplicate: true,
 889→        duplicateType: 'perceptual',
 890→        matchedEventIds: [existing.eventId],
 891→        matchedPointIds: [existing.pointId],
 892→        confidence: Math.max(60, 95 - distance * 7),
 893→        action: 'flag',
 894→        reason: `Near-duplicate photo detected (hamming distance: ${distance}/64)`,
 895→      };
 896→    }
 897→  }
 898→
 899→  // ── Step 3: EXIF fingerprint match ──
 900→  // Same device, same time, same GPS -- different submission
 901→  if (params.photoMetadata.capturedAt && params.photoMetadata.gps) {
 902→    const exifMatches = await findSubmissionsByExifFingerprint(exifFp);
 903→    const otherPoints = exifMatches.filter(e => e.pointId !== params.currentPointId);
 904→    if (otherPoints.length > 0) {
 905→      return {
 906→        isDuplicate: true,
 907→        duplicateType: 'exif_match',
 908→        matchedEventIds: otherPoints.map(e => e.eventId),
 909→        matchedPointIds: [...new Set(otherPoints.map(e => e.pointId))],
 910→        confidence: 80,
 911→        action: 'flag',
 912→        reason: 'Photo has identical EXIF fingerprint (same device, time, GPS) as another submission',
 913→      };
 914→    }
 915→  }
 916→
 917→  return {
 918→    isDuplicate: false,
 919→    duplicateType: 'none',
 920→    matchedEventIds: [],
 921→    matchedPointIds: [],
 922→    confidence: 0,
 923→    action: 'allow',
 924→    reason: null,
 925→  };
 926→}
