1218→
1219→### 4.1 Photo Freshness Validation
1220→
1221→```typescript
1222→// lib/server/photoValidation.ts
1223→
1224→interface PhotoFreshnessResult {
1225→  isFresh: boolean;
1226→  freshnessScore: number;  // 0-100
1227→  capturedAt: string | null;
1228→  submittedAt: string;
1229→  ageMinutes: number | null;
1230→  flags: string[];
1231→}
1232→
1233→function validatePhotoFreshness(params: {
1234→  exifCapturedAt: string | null;
1235→  submissionTime: Date;
1236→  serverReceiveTime: Date;
1237→  isLowEndDevice: boolean;
1238→}): PhotoFreshnessResult {
1239→  const flags: string[] = [];
1240→  let freshnessScore = 50; // Neutral starting point
1241→  let ageMinutes: number | null = null;
1242→
1243→  if (!params.exifCapturedAt) {
1244→    // No EXIF timestamp -- cannot validate freshness
1245→    freshnessScore = params.isLowEndDevice ? 40 : 25;
1246→    flags.push('NO_EXIF_TIMESTAMP');
1247→    return {
1248→      isFresh: true, // Cannot determine, assume fresh
1249→      freshnessScore,
1250→      capturedAt: null,
1251→      submittedAt: params.submissionTime.toISOString(),
1252→      ageMinutes: null,
1253→      flags,
1254→    };
1255→  }
1256→
1257→  const capturedDate = new Date(params.exifCapturedAt);
1258→  const submissionDate = params.submissionTime;
1259→
1260→  // Age of photo in minutes
1261→  ageMinutes = (submissionDate.getTime() - capturedDate.getTime()) / 60000;
1262→
1263→  // ── FRESHNESS RULES ──
1264→
1265→  // Rule 1: Photo timestamp is in the future
1266→  if (ageMinutes < -5) { // Allow 5 minutes of clock skew
1267→    freshnessScore = 10;
1268→    flags.push('FUTURE_TIMESTAMP');
1269→    // Often just a misconfigured phone clock, not fraud
1270→    // But still suspicious
1271→  }
1272→
1273→  // Rule 2: Photo taken within last 30 minutes -- very fresh
1274→  else if (ageMinutes >= 0 && ageMinutes <= 30) {
1275→    freshnessScore = 100;
1276→    // Perfect -- photo was just taken
1277→  }
1278→
1279→  // Rule 3: Photo taken within last 2 hours -- reasonably fresh
1280→  else if (ageMinutes <= 120) {
1281→    freshnessScore = 80;
1282→    // Agent took photos on a field trip, submitting batch later
1283→  }
1284→
1285→  // Rule 4: Photo taken within last 24 hours -- acceptable
1286→  else if (ageMinutes <= 1440) {
1287→    freshnessScore = 60;
1288→    flags.push('PHOTO_STALE_HOURS');
1289→  }
1290→
1291→  // Rule 5: Photo is 1-7 days old -- questionable
1292→  else if (ageMinutes <= 10080) {
1293→    freshnessScore = 30;
1294→    flags.push('PHOTO_STALE_DAYS');
1295→  }
1296→
1297→  // Rule 6: Photo is more than 7 days old -- likely recycled
1298→  else {
1299→    freshnessScore = 10;
1300→    flags.push('PHOTO_RECYCLED');
1301→  }
1302→
1303→  // Rule 7: Photo is more than 1 year old -- definitely recycled
1304→  if (ageMinutes > 525600) {
1305→    freshnessScore = 0;
1306→    flags.push('PHOTO_ANCIENT');
1307→  }
1308→
1309→  // ── CLOCK SKEW COMPENSATION ──
1310→  // Many phones in Cameroon have incorrect clocks
1311→  // If the EXIF timestamp is off by exactly N hours (timezone issue),
1312→  // do not penalize
1313→  const hourOffset = Math.round(ageMinutes / 60);
1314→  if (hourOffset >= 1 && hourOffset <= 12 &&
1315→      Math.abs(ageMinutes - hourOffset * 60) < 10) {
1316→    // Likely timezone misconfiguration -- recover some score
1317→    freshnessScore = Math.min(100, freshnessScore + 30);
1318→    flags.push(`LIKELY_TIMEZONE_OFFSET_${hourOffset}H`);
1319→  }
1320→
1321→  return {
1322→    isFresh: freshnessScore >= 30,
1323→    freshnessScore,
1324→    capturedAt: params.exifCapturedAt,
1325→    submittedAt: params.submissionTime.toISOString(),
1326→    ageMinutes,
1327→    flags,
1328→  };
1329→}
