1332→### 4.2 Photo Content Analysis
1333→
1334→```typescript
1335→// lib/server/photoContentAnalysis.ts
1336→
1337→interface PhotoContentResult {
1338→  contentScore: number;         // 0-100
1339→  isScreenshot: boolean;
1340→  isLikelyOutdoor: boolean;
1341→  matchesExpectedVertical: boolean;
1342→  flags: string[];
1343→}
1344→
1345→// ── SCREENSHOT DETECTION ──
1346→
1347→interface ImageDimensions {
1348→  width: number;
1349→  height: number;

1350→}
1351→
1352→function detectScreenshot(dimensions: ImageDimensions): {
1353→  isScreenshot: boolean;
1354→  confidence: number;
1355→  reason: string | null;
1356→} {
1357→  const { width, height } = dimensions;
1358→
1359→  // Common Android screenshot resolutions
1360→  const ANDROID_SCREENSHOT_RESOLUTIONS = [
1361→    [1080, 2400], [1080, 2340], [1080, 2160], [720, 1600],
1362→    [720, 1560], [720, 1520], [720, 1280], [1440, 3200],
1363→    [1440, 3120], [1440, 2960], [1440, 3040],
1364→  ];
1365→
1366→  // Common iPhone screenshot resolutions
1367→  const IPHONE_SCREENSHOT_RESOLUTIONS = [
1368→    [1170, 2532], [1284, 2778], [1125, 2436], [1242, 2688],
1369→    [750, 1334], [1080, 1920], [1290, 2796], [1179, 2556],
1370→  ];
1371→
1372→  const allScreenshots = [
1373→    ...ANDROID_SCREENSHOT_RESOLUTIONS,
1374→    ...IPHONE_SCREENSHOT_RESOLUTIONS,
1375→  ];
1376→
1377→  for (const [sw, sh] of allScreenshots) {
1378→    if ((width === sw && height === sh) || (width === sh && height === sw)) {
1379→      return {
1380→        isScreenshot: true,
1381→        confidence: 70,
1382→        reason: `Dimensions ${width}x${height} match known screenshot resolution`,
1383→      };
1384→    }
1385→  }
1386→
1387→  // Camera photos typically have aspect ratios of 4:3 or 16:9
1388→  // Screenshots have unusual aspect ratios like 9:19.5
1389→  const ratio = Math.max(width, height) / Math.min(width, height);
1390→  if (ratio > 2.0) {
1391→    return {
1392→      isScreenshot: true,
1393→      confidence: 50,
1394→      reason: `Aspect ratio ${ratio.toFixed(2)} is atypical for camera photos`,
1395→    };
1396→  }
1397→
1398→  return { isScreenshot: false, confidence: 0, reason: null };
1399→}
1400→
1401→// ── PHOTO METADATA INTEGRITY ──
1402→
1403→interface MetadataIntegrityResult {
1404→  isEdited: boolean;
1405→  isDownloaded: boolean;
1406→  confidence: number;
1407→  flags: string[];
1408→}
1409→
1410→function checkMetadataIntegrity(params: {
1411→  exifSoftware: string | null;
1412→  exifMake: string | null;
1413→  exifModel: string | null;
1414→  hasExifGps: boolean;
1415→  hasExifTimestamp: boolean;
1416→  fileSize: number;
1417→  dimensions: ImageDimensions;
1418→  mimeType: string | null;
1419→}): MetadataIntegrityResult {
1420→  const flags: string[] = [];
1421→  let isEdited = false;
1422→  let isDownloaded = false;
1423→
1424→  // ── Editing software detection ──
1425→  const editingSoftware = [
1426→    'photoshop', 'gimp', 'lightroom', 'snapseed', 'vsco',
1427→    'canva', 'picsart', 'exiftool', 'imagemagick',
1428→  ];
1429→  if (params.exifSoftware) {
1430→    const sw = params.exifSoftware.toLowerCase();
1431→    for (const editor of editingSoftware) {
1432→      if (sw.includes(editor)) {
1433→        isEdited = true;
1434→        flags.push(`EDITED_WITH_${editor.toUpperCase()}`);
1435→      }
1436→    }
1437→  }
1438→
1439→  // ── Download indicators ──
1440→  // Photos downloaded from the internet typically lack:
1441→  // - GPS data (stripped by social media platforms)
1442→  // - Device make/model
1443→  // - Original timestamp
1444→  // But DO have:
1445→  // - Standard web image dimensions (800x600, 1200x800, etc.)
1446→  if (!params.hasExifGps && !params.exifMake && !params.hasExifTimestamp) {
1447→    // Triple-null: very suspicious
1448→    flags.push('NO_DEVICE_METADATA');
1449→
1450→    // Common web image dimensions
1451→    const webDimensions = [
1452→      [800, 600], [1024, 768], [1200, 800], [1920, 1080],
1453→      [640, 480], [1280, 720], [960, 640],
1454→    ];
1455→    const { width, height } = params.dimensions;
1456→    for (const [w, h] of webDimensions) {
1457→      if ((width === w && height === h) || (width === h && height === w)) {
1458→        isDownloaded = true;
1459→        flags.push(`WEB_IMAGE_DIMENSIONS_${width}x${height}`);
1460→        break;
1461→      }
1462→    }
1463→  }
1464→
1465→  // ── File size anomalies ──
1466→  // Camera photos are typically 2-10 MB
1467→  // Screenshots: 100KB-1MB
1468→  // Downloaded web images: 50KB-500KB
1469→  // AI-generated: varies widely
1470→  if (params.fileSize < 50000) { // < 50KB
1471→    flags.push('VERY_SMALL_FILE');
1472→  } else if (params.fileSize < 200000 && params.dimensions.width > 1000) {
1473→    flags.push('HIGH_COMPRESSION_RATIO');
1474→    isDownloaded = true;
1475→  }
1476→
1477→  const confidence = flags.length === 0 ? 0 :
1478→    Math.min(90, flags.length * 25);
1479→
1480→  return { isEdited, isDownloaded, confidence, flags };
1481→}
1482→
1483→// ── WEATHER/LIGHTING CONSISTENCY ──
1484→// Simple heuristic: check if submission time of day is consistent
1485→// with expected lighting conditions
1486→// (Full implementation would require image brightness analysis)
1487→
1488→function checkTimeLightingConsistency(params: {
1489→  submissionTimeUTC: Date;
1490→  exifCapturedAtUTC: string | null;
1491→  category: string;
1492→}): { isConsistent: boolean; flags: string[] } {
1493→  const flags: string[] = [];
1494→
1495→  // Cameroon is UTC+1
1496→  const localHour = (params.submissionTimeUTC.getUTCHours() + 1) % 24;
1497→
1498→  // Night submissions (23:00-05:00) for outdoor-only verticals
1499→  const outdoorVerticals = ['billboard', 'fuel_station', 'transport_road'];
1500→  if (outdoorVerticals.includes(params.category) && (localHour >= 23 || localHour < 5)) {
1501→    flags.push('NIGHTTIME_OUTDOOR_SUBMISSION');
1502→  }
1503→
1504→  // Very early morning (04:00-06:00) is unusual for fieldwork
1505→  if (localHour >= 4 && localHour < 6) {
1506→    flags.push('VERY_EARLY_SUBMISSION');
1507→  }
1508→
1509→  return {
1510→    isConsistent: flags.length === 0,
1511→    flags,
1512→  };
1513→}
1514→```
