1626→### 5.3 Scoring Algorithm
1627→
1628→```typescript
1629→// lib/server/fraudScoring.ts
1630→
1631→interface FraudRiskComponents {
1632→  gpsRisk: number;           // 0-100
1633→  photoRisk: number;         // 0-100
1634→  temporalRisk: number;      // 0-100
1635→  agentHistoryRisk: number;  // 0-100
1636→  behavioralRisk: number;    // 0-100
1637→}
1638→
1639→interface FraudRiskResult {
1640→  compositeScore: number;     // 0-100
1641→  components: FraudRiskComponents;
1642→  action: 'auto_approve' | 'soft_review' | 'hard_review' | 'auto_reject';
1643→  xpAction: 'award' | 'escrow' | 'deny';
1644→  flags: string[];
1645→  confidenceInScore: number;  // 0-100, how confident we are in our own score
1646→}
1647→
1648→const WEIGHTS = {
1649→  gps: 0.25,
1650→  photo: 0.25,
1651→  temporal: 0.15,
1652→  agentHistory: 0.20,
1653→  behavioral: 0.15,
1654→};
1655→
1656→function computeFraudRiskScore(params: {
1657→  // GPS signals
1658→  gpsValidation: GpsValidationResult;
1659→
1660→  // Photo signals
1661→  photoDuplicate: DuplicateCheckResult;
1662→  photoFreshness: PhotoFreshnessResult;
1663→  metadataIntegrity: MetadataIntegrityResult;
1664→  screenshotDetection: { isScreenshot: boolean; confidence: number };
1665→
1666→  // Temporal signals
1667→  recentSubmissionCount15min: number;
1668→  recentSubmissionCount1hr: number;
1669→  lastSubmissionLocation: SubmissionLocation | null;
1670→  lastSubmissionTime: Date | null;
1671→  currentLocation: SubmissionLocation;
1672→  currentTime: Date;
1673→  isOfflineBatch: boolean;
1674→
1675→  // Agent history signals
1676→  accountAgeDays: number;
1677→  totalSubmissions: number;
1678→  priorFraudFlags: number;
1679→  priorRejections: number;
1680→  userTrustScore: number;
1681→  consecutiveClean: number;
1682→
1683→  // Behavioral signals
1684→  selfEnrichmentCount: number;
1685→  samePointEnrichments: number;
1686→  deviceSharedWithOtherUsers: boolean;
1687→  ipIsVpnOrDatacenter: boolean;
1688→}): FraudRiskResult {
1689→  const flags: string[] = [];
1690→
1691→  // ── GPS RISK (0-100) ──
1692→  // Invert the GPS confidence score
1693→  const gpsRisk = 100 - params.gpsValidation.gpsConfidenceScore;
1694→  if (gpsRisk > 50) flags.push('HIGH_GPS_RISK');
1695→
1696→  // ── PHOTO RISK (0-100) ──
1697→  let photoRisk = 0;
1698→
1699→  // Duplicate detection is the strongest photo signal
1700→  if (params.photoDuplicate.action === 'reject') {
1701→    photoRisk += 80;
1702→    flags.push('PHOTO_DUPLICATE_REJECT');
1703→  } else if (params.photoDuplicate.action === 'flag') {
1704→    photoRisk += 40;
1705→    flags.push('PHOTO_DUPLICATE_FLAG');
1706→  }
1707→
1708→  // Freshness
1709→  photoRisk += Math.round((100 - params.photoFreshness.freshnessScore) * 0.3);
1710→
1711→  // Metadata integrity
1712→  if (params.metadataIntegrity.isEdited) {
1713→    photoRisk += 25;
1714→    flags.push('PHOTO_EDITED');
1715→  }
1716→  if (params.metadataIntegrity.isDownloaded) {
1717→    photoRisk += 30;
1718→    flags.push('PHOTO_DOWNLOADED');
1719→  }
1720→
1721→  // Screenshot
1722→  if (params.screenshotDetection.isScreenshot) {
1723→    photoRisk += 20;
1724→    flags.push('SCREENSHOT_DETECTED');
1725→  }
1726→
1727→  photoRisk = Math.min(100, photoRisk);
1728→
1729→  // ── TEMPORAL RISK (0-100) ──
1730→  let temporalRisk = 0;
1731→
1732→  // Velocity (adjusted for offline batches)
1733→  if (!params.isOfflineBatch) {
1734→    if (params.recentSubmissionCount15min > 10) temporalRisk += 50;
1735→    else if (params.recentSubmissionCount15min > 5) temporalRisk += 25;
1736→    else if (params.recentSubmissionCount15min > 3) temporalRisk += 10;
1737→  } else {
1738→    // Offline batch: use relaxed thresholds
1739→    if (params.recentSubmissionCount15min > 20) temporalRisk += 30;
1740→    else if (params.recentSubmissionCount15min > 15) temporalRisk += 15;
1741→  }
1742→
1743→  // Impossible travel
1744→  if (params.lastSubmissionLocation && params.lastSubmissionTime) {
1745→    const distKm = haversineKm(params.lastSubmissionLocation, params.currentLocation);
1746→    const timeH = (params.currentTime.getTime() - params.lastSubmissionTime.getTime()) / 3600000;
1747→    if (timeH > 0) {
1748→      const speedKmh = distKm / timeH;
1749→      if (speedKmh > 200) { temporalRisk += 50; flags.push('IMPOSSIBLE_TRAVEL'); }
1750→      else if (speedKmh > 80) { temporalRisk += 25; flags.push('HIGH_VELOCITY'); }
1751→    }
1752→  }
1753→
1754→  // Late-night submissions (Cameroon is UTC+1)
1755→  const localHour = (params.currentTime.getUTCHours() + 1) % 24;
1756→  if (localHour >= 23 || localHour < 5) temporalRisk += 10;
1757→
1758→  temporalRisk = Math.min(100, temporalRisk);
1759→
1760→  // ── AGENT HISTORY RISK (0-100) ──
1761→  let agentHistoryRisk = 0;
1762→
1763→  // New account penalty
1764→  if (params.accountAgeDays < 1) agentHistoryRisk += 25;
1765→  else if (params.accountAgeDays < 7) agentHistoryRisk += 15;
1766→  else if (params.accountAgeDays < 30) agentHistoryRisk += 5;
1767→
1768→  // No submission history
1769→  if (params.totalSubmissions === 0) agentHistoryRisk += 15;
1770→
1771→  // Prior fraud history
1772→  agentHistoryRisk += Math.min(40, params.priorFraudFlags * 10);
1773→  agentHistoryRisk += Math.min(20, params.priorRejections * 5);
1774→
1775→  // Inverse of trust score
1776→  agentHistoryRisk += Math.round((100 - params.userTrustScore) * 0.2);
1777→
1778→  // Consecutive clean streak bonus (reduces risk)
1779→  if (params.consecutiveClean > 20) agentHistoryRisk = Math.max(0, agentHistoryRisk - 15);
1780→  else if (params.consecutiveClean > 10) agentHistoryRisk = Math.max(0, agentHistoryRisk - 10);
1781→
1782→  agentHistoryRisk = Math.min(100, agentHistoryRisk);
1783→
1784→  // ── BEHAVIORAL RISK (0-100) ──
1785→  let behavioralRisk = 0;
1786→
1787→  if (params.selfEnrichmentCount > 5) behavioralRisk += 30;
1788→  else if (params.selfEnrichmentCount > 2) behavioralRisk += 15;
1789→
1790→  if (params.samePointEnrichments > 3) behavioralRisk += 25;
1791→
1792→  if (params.deviceSharedWithOtherUsers) behavioralRisk += 15;
1793→  if (params.ipIsVpnOrDatacenter) {
1794→    behavioralRisk += 20;
1795→    flags.push('VPN_OR_DATACENTER_IP');
1796→  }
1797→
1798→  behavioralRisk = Math.min(100, behavioralRisk);
1799→
1800→  // ── COMPOSITE SCORE ──
1801→  const compositeScore = Math.round(
1802→    WEIGHTS.gps * gpsRisk +
1803→    WEIGHTS.photo * photoRisk +
1804→    WEIGHTS.temporal * temporalRisk +
1805→    WEIGHTS.agentHistory * agentHistoryRisk +
1806→    WEIGHTS.behavioral * behavioralRisk
1807→  );
1808→
1809→  // ── DETERMINE ACTION ──
1810→  let action: FraudRiskResult['action'];
1811→  let xpAction: FraudRiskResult['xpAction'];
1812→
1813→  if (compositeScore <= 25) {
1814→    action = 'auto_approve';
1815→    xpAction = 'award';
1816→  } else if (compositeScore <= 50) {
1817→    action = 'soft_review';
1818→    xpAction = 'award';      // Award XP but reversible if review finds fraud
1819→  } else if (compositeScore <= 75) {
1820→    action = 'hard_review';
1821→    xpAction = 'escrow';     // Hold XP until admin approves
1822→  } else {
1823→    action = 'auto_reject';
1824→    xpAction = 'deny';
1825→  }
1826→
1827→  // ── OVERRIDE: Critical flags force escalation ──
1828→  if (flags.includes('PHOTO_DUPLICATE_REJECT')) {
1829→    action = 'auto_reject';
1830→    xpAction = 'deny';
1831→  }
1832→  if (flags.includes('IMPOSSIBLE_TRAVEL') && gpsRisk > 60) {
1833→    action = 'auto_reject';
1834→    xpAction = 'deny';
1835→  }
1836→
1837→  // ── CONFIDENCE IN OUR OWN SCORE ──
1838→  // Higher when we have more signals to work with
1839→  let confidenceInScore = 50;
1840→  if (params.gpsValidation.exifMatchResult !== 'no_exif') confidenceInScore += 15;
1841→  if (params.gpsValidation.ipMatchResult !== 'unknown') confidenceInScore += 10;
1842→  if (params.gpsValidation.mockLocationResult !== 'unknown') confidenceInScore += 10;
1843→  if (params.totalSubmissions > 10) confidenceInScore += 10;
1844→  if (params.photoDuplicate.confidence > 0) confidenceInScore += 5;
1845→
1846→  return {
1847→    compositeScore: Math.min(100, Math.max(0, compositeScore)),
1848→    components: {
1849→      gpsRisk,

1850→      photoRisk,
1851→      temporalRisk,
1852→      agentHistoryRisk,
1853→      behavioralRisk,
1854→    },
1855→    action,
1856→    xpAction,
1857→    flags,
1858→    confidenceInScore: Math.min(100, confidenceInScore),
1859→  };
1860→}
1861→```
