1971→    minApproved: 0,
1972→    privileges: [
1973→      'All submissions blocked',
1974→      'Must appeal to admin to restore',
1975→      'Cannot earn XP',
1976→    ],
1977→  },
1978→};
1979→
1980→// ── TRUST SCORE UPDATE LOGIC ──
1981→
1982→function updateAgentTrust(
1983→  profile: AgentTrustProfile,
1984→  event: 'submission_approved' | 'submission_flagged' | 'submission_rejected' |
1985→         'mystery_audit_passed' | 'mystery_audit_failed' | 'peer_validation'
1986→): AgentTrustProfile {
1987→  const updated = { ...profile };
1988→
1989→  switch (event) {
1990→    case 'submission_approved':
1991→      updated.totalApproved++;
1992→      updated.consecutiveClean++;
1993→      // Gradual increase: +1 per clean, +2 on streak >10
1994→      const bonus = updated.consecutiveClean > 10 ? 2 : 1;
1995→      updated.trustScore = Math.min(100, updated.trustScore + bonus);
1996→      break;
1997→
1998→    case 'submission_flagged':
1999→      updated.totalFlagged++;
2000→      updated.consecutiveClean = 0;
2001→      updated.trustScore = Math.max(0, updated.trustScore - 5);
2002→      updated.lastFraudFlag = new Date().toISOString();
2003→      break;
2004→
2005→    case 'submission_rejected':
2006→      updated.totalRejected++;
2007→      updated.consecutiveClean = 0;
2008→      updated.trustScore = Math.max(0, updated.trustScore - 15);
2009→      updated.lastFraudFlag = new Date().toISOString();
2010→      break;
2011→
2012→    case 'mystery_audit_passed':
2013→      // Strong positive signal: agent's data verified on the ground
2014→      updated.trustScore = Math.min(100, updated.trustScore + 10);
2015→      updated.consecutiveClean += 5; // Equivalent to 5 clean submissions
2016→      break;
2017→
2018→    case 'mystery_audit_failed':
2019→      // Strong negative signal: agent's data found to be wrong on the ground
2020→      updated.trustScore = Math.max(0, updated.trustScore - 25);
2021→      updated.consecutiveClean = 0;
2022→      updated.lastFraudFlag = new Date().toISOString();
2023→      break;
2024→
2025→    case 'peer_validation':
2026→      // Another agent confirmed this agent's submission
2027→      updated.trustScore = Math.min(100, updated.trustScore + 1);
2028→      break;
2029→  }
2030→
2031→  // ── INACTIVITY DECAY ──
2032→  // Trust decays by 1 point per 30 days of inactivity
2033→  if (updated.lastActivity) {
2034→    const daysSinceActivity = (Date.now() - new Date(updated.lastActivity).getTime()) / 86400000;
2035→    const decayPoints = Math.floor(daysSinceActivity / 30);
2036→    if (decayPoints > 0) {
2037→      updated.trustScore = Math.max(0, updated.trustScore - decayPoints);
2038→    }
2039→  }
2040→
2041→  // ── UPDATE TIER ──
2042→  if (updated.trustScore >= TIER_RULES.elite.minTrustScore &&
2043→      updated.totalApproved >= TIER_RULES.elite.minApproved) {
2044→    updated.tier = 'elite';
2045→  } else if (updated.trustScore >= TIER_RULES.trusted.minTrustScore &&
2046→             updated.totalApproved >= TIER_RULES.trusted.minApproved) {
2047→    updated.tier = 'trusted';
2048→  } else if (updated.trustScore >= TIER_RULES.standard.minTrustScore) {
2049→    updated.tier = 'standard';
2050→  } else if (updated.trustScore >= 10) {
2051→    updated.tier = 'new';
2052→  } else {
2053→    updated.tier = 'suspended';
2054→  }
2055→
2056→  updated.lastActivity = new Date().toISOString();
2057→  return updated;
2058→}
2059→```
